        [Fact]
        public void Test_ResultTablesEmptyWhenNoTables()
        {
            // Result tables array is empty when input has no tables
            var result = HtmlToMarkdownRs.Convert("<p>No tables here</p>", new ConversionOptions { IncludeDocumentStructure = true });
