        [Fact]
        public void Test_ResultTablesMultiple()
        {
            // Multiple tables each appear in the tables array
            var result = HtmlToMarkdownRs.Convert("<table><tr><th>A</th></tr><tr><td>1</td></tr></table><p>Between</p><table><tr><th>B</th></tr><tr><td>2</td></tr></table>", new ConversionOptions { IncludeDocumentStructure = true });
    Assert.True(result.Tables.Count >= 2, "expected at least 2 elements");

        }

        [Fact]
