            // Simple table populates the tables array in result
            var result = HtmlToMarkdownRs.Convert("<table><thead><tr><th>Name</th><th>Age</th></tr></thead><tbody><tr><td>Alice</td><td>30</td></tr></tbody></table>", new ConversionOptions { IncludeDocumentStructure = true });
